class SegmentTree {
    let n: Int
    var tree: [Int]
    init(n: Int) {
        self.n = n
        tree = [Int](repeating: Int.min, count: 4 * n)
    }

    func update(at index: Int, to value: Int) {
        updateHelper(node: 0, l: 0, r: n - 1, pos: index, val: value)
    }

    private func updateHelper(node: Int, l: Int, r: Int, pos: Int, val: Int) {
        if l == r {
            tree[node] = val
            return
        }
        let mid = (l + r) / 2
        if pos <= mid {
            updateHelper(node: 2 * node + 1, l: l, r: mid, pos: pos, val: val)
        } else {
            updateHelper(node: 2 * node + 2, l: mid + 1, r: r, pos: pos, val: val)
        }
        tree[node] = max(tree[2 * node + 1], tree[2 * node + 2])
    }

    func query(_ left: Int, _ right: Int) -> Int {
        return queryHelper(node: 0, l: 0, r: n - 1, ql: left, qr: right)
    }

    private func queryHelper(node: Int, l: Int, r: Int, ql: Int, qr: Int) -> Int {
        if ql > r || qr < l {
            return Int.min
        }
        if ql <= l && r <= qr {
            return tree[node]
        }
        let mid = (l + r) / 2
        let leftRes = queryHelper(node: 2 * node + 1, l: l, r: mid, ql: ql, qr: qr)
        let rightRes = queryHelper(node: 2 * node + 2, l: mid + 1, r: r, ql: ql, qr: qr)
        return max(leftRes, rightRes)
    }
}

func solve(weight: Array<Int64>) -> Int64 {
    let n = weight.count
    if n < 2 {
        return 0
    }
    var left_bound = [Int](repeating: -1, count: n)
    var stack = [Int]()
    for i in 0..<n {
        while !stack.isEmpty {
            let lastIndex = stack.last!
            if weight[lastIndex] <= weight[i] {
                stack.removeLast()
            } else {
                break
            }
        }
        if !stack.isEmpty {
            left_bound[i] = stack.last!
        } else {
            left_bound[i] = -1
        }
        stack.append(i)
    }

    let segTree = SegmentTree(n: n + 1)
    segTree.update(at: 0, to: 0)

    var dp = [Int](repeating: 0, count: n)
    for i in 0..<n {
        if i > 0 {
            dp[i] = dp[i - 1]
        } else {
            dp[i] = 0
        }
        if left_bound[i] != -1 {
            let best = segTree.query(0, left_bound[i])
            let candidate = best + 1
            if candidate > dp[i] {
                dp[i] = candidate
            }
        }
        segTree.update(at: i + 1, to: dp[i])
    }
    return Int64(dp[n - 1])
}
```

### Explanation
1. **Stack for Previous Greater Element**: We traverse the array from left to right, maintaining a stack to keep track of indices. For each element, we pop elements from the stack if they are less than or equal to the current element. The top of the stack, if not empty, gives the nearest previous greater element's index.
2. **Segment Tree for Efficient Queries**: The segment tree helps in efficiently querying the maximum number of shipments achievable up to any index. This allows us to determine the optimal starting point for a new shipment ending at the current element.
3. **Dynamic Programming Array**: The `dp` array is updated for each element. If a valid starting index (from the stack) is found, we query the segment tree for the maximum shipments achievable before this index and update `dp[i]` to include the new shipment if it increases the count.
4. **Result Extraction**: The value `dp[n-1]` gives the maximum number of non-overlapping balanced shipments achievable for the entire array, which is returned as the result.

This approach efficiently combines stack processing with dynamic programming and segment tree operations to solve the problem in optimal time complexity, O(n log n), suitable for large input sizes.

To solve this problem, we need to find the maximum number of non-overlapping, contiguous balanced shipments in an array of package weights. A balanced shipment is defined as a contiguous subarray where the last element is strictly less than the maximum weight in that subarray.

### Approach
1. **Problem Analysis**: The problem requires partitioning the array into the maximum number of non-overlapping contiguous subarrays (shipments) where each shipment must satisfy the condition that its last element is strictly less than the maximum element in that subarray. Note that shipments must be contiguous and non-overlapping, but we can skip any packages as needed.

2. **Key Insight**: For any shipment ending at index `i`, there must exist at least one element in the shipment (before `i`) that is greater than `weight[i]`. This element can be found using a monotonic stack to track the nearest previous greater element for each index.

3. **Dynamic Programming (DP) Setup**: 
   - **DP Array**: `dp[i]` represents the maximum number of balanced shipments possible for the prefix of the array ending at index `i`.
   - **State Transition**: For each index `i`, if there exists a previous greater element, we consider forming a shipment ending at `i` starting from some index `k` (where `k` ranges from 0 to the index of the previous greater element). The DP value is updated based on whether forming this shipment increases the count of shipments.

4. **Efficiency Optimization**: 
   - **Monotonic Stack**: Used to efficiently compute the nearest previous greater element for each index in O(n) time.
   - **Prefix Maximum Arrays**: `D_arr` and `M_arr` are used to store DP values and their prefix maxima, respectively, allowing O(1) access to the maximum DP value needed for transitions.

### Solution Code
```swift
func solve(weight: [Int64]) -> Int64 {
    let n = weight.count
    guard n >= 2 else { return 0 }

    var prevGreater = [Int](repeating: -1, count: n)
    var stack = [Int]()

    for i in 0..<n {
        while !stack.isEmpty && weight[stack.last!] <= weight[i] {
            stack.removeLast()
        }
        if !stack.isEmpty {
            prevGreater[i] = stack.last!
        }
        stack.append(i)
    }

    var dp = [Int64](repeating: 0, count: n)
    var D_arr: [Int64] = [0]
    var M_arr: [Int64] = [0]

    for i in 0..<n {
        var candidate: Int64 = -1
        if prevGreater[i] != -1 {
            candidate = M_arr[prevGreater[i]] + 1
        }

        let skip_value: Int64 = i > 0 ? dp[i-1] : 0

        if candidate == -1 {
            dp[i] = skip_value
        } else {
            dp[i] = max(skip_value, candidate)
        }

        D_arr.append(dp[i])
        let currentMax = max(M_arr.last!, dp[i])
        M_arr.append(currentMax)
    }

    return dp[n-1]
}
```

### Explanation
1. **Finding Previous Greater Elements**: Using a monotonic stack, we iterate through the array to find for each element the nearest previous element that is strictly greater. This helps in determining valid starting points for shipments ending at each index.

2. **Dynamic Programming Setup**: 
   - **Initialization**: The `dp` array is initialized to store the maximum number of shipments up to each index. `D_arr` starts with `0` to represent the base state (no elements processed), and `M_arr` stores the prefix maxima of `D_arr`.

3. **Processing Each Index**:
   - **Candidate Calculation**: For each index `i`, if a previous greater element exists, the potential shipments ending at `i` are considered by taking the maximum prefix DP value up to the previous greater element's index.
   - **State Update**: The DP value at `i` is updated to the maximum between skipping `i` or forming a new shipment ending at `i`.
   - **Updating Auxiliary Arrays**: `D_arr` and `M_arr` are updated to include the current DP value, ensuring efficient maximum queries in subsequent steps.

4. **Result Extraction**: The value at `dp[n-1]` gives the maximum number of balanced shipments for the entire array, which is returned as the result.

This approach efficiently computes the solution by leveraging dynamic programming and monotonic stack techniques to handle the constraints optimally.

To solve this problem, we need to find the maximum number of non-overlapping balanced shipments that can be formed from a given array of package weights. A balanced shipment is defined as a contiguous subarray where the last element is strictly less than the maximum weight in that subarray. 

### Approach
1. **Problem Analysis**: The key observation is that for any shipment ending at index `i`, there must exist at least one element to the left of `i` that is greater than `weight[i]`. This element must be included in the shipment to ensure the maximum weight in the shipment is greater than `weight[i]`.

2. **Precompute Last Greater Elements**: We first compute an array `last_greater` where each element at index `i` stores the index of the nearest element to the left of `i` that is greater than `weight[i]`. This helps in determining the valid starting points for shipments ending at each index.

3. **Dynamic Programming (DP) Setup**: We use a DP array where `dp[i]` represents the maximum number of balanced shipments that can be formed in the prefix of the array up to the `(i-1)`-th element (0-based index). Additionally, we maintain an `mx` array to store the maximum DP value encountered up to each index for efficient look-up.

4. **DP Transition**:
   - For each element at index `i` (0-based), if there is no greater element to its left (`last_greater[i] == -1`), we cannot form a shipment ending at `i`, so `dp[i+1]` remains the same as `dp[i]`.
   - If there is a greater element (`last_greater[i] != -1`), we consider the maximum DP value up to the index `last_greater[i]` (using the `mx` array) to determine if forming a new shipment ending at `i` would increase the count of shipments.

5. **Result Extraction**: The solution is derived from `dp[n]`, which contains the result for the entire array.

### Solution Code
```cangjie
#include <vector>
#include <cstdint>

function solve(weight: Array<Int64>): Int64 {
    var n = weight.size();
    var last_greater = std::vector<Int64>(n, -1);
    var stack = std::vector<Int64>();

    for (var i = 0; i < n; i++) {
        while (!stack.empty() && weight[stack.back()] <= weight[i]) {
            stack.pop_back();
        }
        if (!stack.empty()) {
            last_greater[i] = stack.back();
        } else {
            last_greater[i] = -1;
        }
        stack.push_back(i);
    }

    var dp = std::vector<Int64>(n + 1, 0);
    var mx = std::vector<Int64>(n + 1, 0);

    for (var i = 1; i <= n; i++) {
        var k = last_greater[i - 1];
        if (k == -1) {
            dp[i] = dp[i - 1];
        } else {
            dp[i] = std::max(dp[i - 1], mx[k] + 1);
        }
        mx[i] = std::max(mx[i - 1], dp[i]);
    }

    return dp[n];
}
```

### Explanation
1. **Precompute `last_greater`**: Using a stack, we efficiently find for each element the nearest greater element to its left. This helps in identifying valid starting points for shipments ending at each index.
2. **Dynamic Programming Setup**: The `dp` array tracks the maximum number of balanced shipments for each prefix of the array. The `mx` array stores the maximum value in the `dp` array up to each index for O(1) access during transitions.
3. **DP Transition**: For each element, if there is a greater element to its left, we consider forming a new shipment starting before or at the greater element's index. The DP value is updated by comparing the current count with the count obtained by including the new shipment.
4. **Result**: The value `dp[n]` gives the solution for the entire array, representing the maximum number of non-overlapping balanced shipments possible.

This approach efficiently leverages dynamic programming and stack-based preprocessing to solve the problem in linear time, making it suitable for large input sizes.
